sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	function TestCase_BusinessProcessValidate(business_process,bDetailed,vExpected)
	{
		function TestCase_BusinessProcessValidate_CheckResult(vInput,vExpected,vResult)
		{
			if (GetBoolValue(bDetailed) == false)
			{
				return (vExpected == vResult);
			}

			if (vExpected === false)
			{
				return GetBoolValue(GetValue(vResult,'valid'));
			}

			if (IsObject(vExpected))
			{
				var bExpectedValid = GetBoolValue(GetValue(vExpected,'valid'));
				var nExpectedErrors = GetIntegerValue(GetValue(vExpected,'errors'));
				var nExpectedWarnings = GetIntegerValue(GetValue(vExpected,'warnings'));
				var nExpectedNotes = GetIntegerValue(GetValue(vExpected,'notes'));

				if (bExpectedValid != GetBoolValue(GetValue(vResult,'valid')))
				{
					test.Log('Valid mismatch!');
					return false;
				}
				var aErrors = GetArrayValue(GetValue(vResult,'errors'));
				if (nExpectedErrors != aErrors.length)
				{
					test.Log('Errors mismatch!');
					return false;
				}
				var aWarnings = GetArrayValue(GetValue(vResult,'warnings'));
				if (nExpectedWarnings != aWarnings.length)
				{
					test.Log('Warnings mismatch!');
					return false;
				}
				var aNotes = GetArrayValue(GetValue(vResult,'notes'));
				if (nExpectedNotes != aNotes.length)
				{
					test.Log('Notes mismatch!');
					return false;
				}
			}
			return true;
		}
		
		test.TestCase(
			'Function BusinessProcessValidate()',
			BusinessProcessValidate,
			{
				'business_process': business_process,
				'bDetailed': bDetailed
			},
			vExpected,
			TestCase_BusinessProcessValidate_CheckResult);
	}
		
	TestCase_BusinessProcessValidate(null,null,false);
	TestCase_BusinessProcessValidate(null,false,false);
	TestCase_BusinessProcessValidate(null,true,{ valid: false, errors: 1 });

	var business_process = {};
	TestCase_BusinessProcessValidate(business_process,false,false);
	TestCase_BusinessProcessValidate(business_process,true,{ valid: false, errors: 1 });

	var business_process = BusinessProcessGetExample();
	TestCase_BusinessProcessValidate(business_process,false,true);
	TestCase_BusinessProcessValidate(business_process,true,{ valid: true, errors: 0, warnings: 0, notes: 0 });

	var business_process = BusinessProcessGetExample();
	delete business_process.id;
	TestCase_BusinessProcessValidate(business_process,false,false);
	TestCase_BusinessProcessValidate(business_process,true,{ valid: false, errors: 1, warnings: 0, notes: 0 });

	var business_process = BusinessProcessGetExample();
	delete business_process.name;
	TestCase_BusinessProcessValidate(business_process,false,false);
	TestCase_BusinessProcessValidate(business_process,true,{ valid: false, errors: 1, warnings: 0, notes: 0 });

	var business_process = BusinessProcessGetExample();
	delete business_process.description;
	TestCase_BusinessProcessValidate(business_process,false,true);
	TestCase_BusinessProcessValidate(business_process,true,{ valid: true, errors: 0, warnings: 1, notes: 0 });


	var business_process = BusinessProcessGetExample();
	delete business_process.id;
	delete business_process.description;
	TestCase_BusinessProcessValidate(business_process,false,false);
	TestCase_BusinessProcessValidate(business_process,true,{ valid: false, errors: 1, warnings: 1, notes: 0 });



	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
